import{_ as s,c as a,a as n,o as i}from"./app-CEcM0piI.js";const l={};function t(r,e){return i(),a("div",null,e[0]||(e[0]=[n(`<p>对于js代码有些浏览器还不支持es6语法，因此在使用es6语法的项目需要使用bable将其编译成es5规范的语法的代码 bable通常在dev环境下使用</p><ul><li>bable-loader：提供bable的接口</li><li>@bable/core：bable的核心，编译需要bable核心参与</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm install bable-loader @bable/core --save-dev</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>从es6到es5中也是有多种规范，如果不指定使用哪种规范bableloader不会工作 通常使用的规范是preset-env，需要安装</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm install @bable/preset-env --save-dev</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="配置文件" tabindex="-1"><a class="header-anchor" href="#配置文件"><span>配置文件</span></a></h1><p>bable的配置文件在<code>.bablerc</code>中</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>presets:[</span></span>
<span class="line"><span>	[</span></span>
<span class="line"><span>		&#39;@bable/preset-env&#39;,</span></span>
<span class="line"><span>		{</span></span>
<span class="line"><span>			targets:{</span></span>
<span class="line"><span>				browsers:[</span></span>
<span class="line"><span>					&quot;&gt;1%&quot;,</span></span>
<span class="line"><span>					&quot;last 2 versions&quot;,</span></span>
<span class="line"><span>					&quot;not ie&lt;=8&quot;</span></span>
<span class="line"><span>				]</span></span>
<span class="line"><span>			}</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	]</span></span>
<span class="line"><span>]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="预设" tabindex="-1"><a class="header-anchor" href="#预设"><span>预设</span></a></h3><ul><li>@babel/preset-env：—个智能预设，允许您使用最新的JavaScript。I</li><li>@babel/preset-react：一个用来编译Reactjsx语法的预设</li><li>@babel/preset-typescript：一个用来编译TypeScript语法的预设</li></ul><h3 id="插件" tabindex="-1"><a class="header-anchor" href="#插件"><span>插件</span></a></h3><p>Babel为编译的每个文件都插入了辅助代码，使代码体积过大！ Babel对一些公共方法使用了非常小的辅助代码，比如_extend。默认情况下会被添加到每一个需要它的文件中。</p><p>@babel/plugin-transform-runtime：禁用了Babel自动对每个文件的runtime注入，而是引l入 gbabel/plugin-transform-runtime并且使所有辅助代码从这里引用。</p>`,13)]))}const d=s(l,[["render",t]]),c=JSON.parse('{"path":"/front/engineering/2/","title":"2 bable","lang":"zh-CN","frontmatter":{"title":"2 bable","createTime":"2025/06/18 21:09:36","permalink":"/front/engineering/2/"},"readingTime":{"minutes":1.08,"words":324},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/工程化/2 bable.md","headers":[]}');export{d as comp,c as data};
